import { createDbClient } from "../db/client.js";

const db = createDbClient();

await db.connect();

// Make users.id auto-generated so INSERTs don't need to specify id.
await db.query(`ALTER TABLE public.users ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY;`);

const verify = await db.query(
  `
  select
    column_name,
    data_type,
    is_nullable,
    column_default
  from information_schema.columns
  where table_schema = 'public'
    and table_name = 'users'
    and column_name = 'id'
  `.trim()
);

console.table(verify.rows);

await db.end();

